document.addEventListener("DOMContentLoaded",()=>{if(console.log("test"),window.location.pathname.includes("/allocate-ticket")){const saved=localStorage.getItem("orderSummary");if(saved){const data=JSON.parse(saved);document.getElementById("payment-breakdown").innerHTML=data.breakdown,document.getElementById("subtotal-price").textContent=data.subtotal,document.getElementById("display-discount-value-summary").textContent=data.discount,document.getElementById("display-discount-name").textContent=data.discountName,document.getElementById("display-discount-code").textContent=data.discountCode,document.getElementById("display-discount-value").textContent=data.discountValue,document.getElementById("tax-price").textContent=data.tax,document.getElementById("proccessing-price").textContent=data.processing,document.getElementById("total-price").textContent=data.total,data.discount&&"$0.00"!==data.discount&&(document.querySelector(".discount-summary").classList.remove("is_not_visible"),document.querySelector(".discount-summary-card").classList.remove("is_not_visible"))}}});